import { useEffect, useMemo, useState } from 'react';
import { Link, useParams } from 'react-router-dom';
import AdminMentorLayout from '../components/AdminMentorLayout.jsx';
import { ErrorState, LoadingState } from '../components/LoadingState.jsx';
import StatusBadge from '../components/StatusBadge.jsx';
import { adminMentorApi } from '../services/api.js';
import { formatDateTime } from '../utils/formatters.js';

const MIN_FEEDBACK_LENGTH = 10;

export default function ReviewSubmissionPage() {
  const { submissionId } = useParams();
  const [submission, setSubmission] = useState(null);
  const [form, setForm] = useState({ result: 'PASS', feedback: '' });
  const [reviewResult, setReviewResult] = useState(null);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    let mounted = true;

    adminMentorApi
      .getReviewSubmission(submissionId)
      .then((response) => {
        if (mounted) {
          setSubmission(response.data);
          setError('');
        }
      })
      .catch((requestError) => {
        if (mounted) {
          setError(requestError.message);
        }
      })
      .finally(() => {
        if (mounted) {
          setLoading(false);
        }
      });

    return () => {
      mounted = false;
    };
  }, [submissionId]);

  const feedbackLength = form.feedback.trim().length;
  const canSubmit = feedbackLength >= MIN_FEEDBACK_LENGTH && !submitting && !reviewResult;

  const feedbackHelp = useMemo(() => {
    if (feedbackLength >= MIN_FEEDBACK_LENGTH) {
      return `${feedbackLength} characters`;
    }

    return `Need at least ${MIN_FEEDBACK_LENGTH - feedbackLength} more characters`;
  }, [feedbackLength]);

  const updateForm = (fieldName, value) => {
    setForm((current) => ({ ...current, [fieldName]: value }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setError('');

    if (!canSubmit) {
      setError('Feedback phai co it nhat 10 ky tu truoc khi gui review.');
      return;
    }

    setSubmitting(true);

    try {
      // Gia lap luong duyet bai: backend that phai kiem tra assignment, chong review trung va ghi project_reviews + mentor_feedbacks trong transaction.
      const response = await adminMentorApi.submitReview(submissionId, form);
      setReviewResult(response.data);
      setSubmission((current) => (current ? { ...current, status: 'REVIEWED' } : current));
    } catch (requestError) {
      setError(requestError.message || 'Khong the gui review.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <AdminMentorLayout
      area="mentor"
      title="Review Submission"
      subtitle="Cham final project voi ket qua PASS/FAIL va feedback cho learner."
    >
      <div className="mb-3">
        <Link className="btn btn-outline-secondary btn-sm" to="/mentor/review-queue">
          Back to queue
        </Link>
      </div>

      {loading ? <LoadingState message="Dang tai chi tiet bai nop..." /> : null}
      {!loading && error ? <ErrorState message={error} /> : null}

      {!loading && submission ? (
        <div className="row g-4">
          <div className="col-12 col-xl-7">
            <div className="card admin-mentor-card h-100">
              <div className="card-header bg-white d-flex justify-content-between align-items-center">
                <h2 className="h5 mb-0">Submission detail</h2>
                <StatusBadge status={submission.status} />
              </div>
              <div className="card-body">
                <div className="row g-3">
                  <div className="col-12 col-md-6">
                    <span className="small text-secondary d-block">Learner</span>
                    <strong>{submission.learnerName}</strong>
                    <p className="small text-secondary mb-0">{submission.learnerEmail}</p>
                  </div>
                  <div className="col-12 col-md-6">
                    <span className="small text-secondary d-block">Course</span>
                    <strong>{submission.courseTitle}</strong>
                    <p className="small text-secondary mb-0">Attempt #{submission.attemptNo}</p>
                  </div>
                  <div className="col-12 col-md-6">
                    <span className="small text-secondary d-block">Submitted at</span>
                    <strong>{formatDateTime(submission.submittedAt)}</strong>
                  </div>
                  <div className="col-12 col-md-6">
                    <span className="small text-secondary d-block">Project links</span>
                    <a className="me-3" href={submission.projectUrl} rel="noreferrer" target="_blank">
                      Repository
                    </a>
                    {submission.demoUrl ? (
                      <a href={submission.demoUrl} rel="noreferrer" target="_blank">
                        Demo
                      </a>
                    ) : null}
                  </div>
                </div>

                <hr />

                <h3 className="h6">Summary</h3>
                <p className="text-secondary">{submission.summary}</p>

                <h3 className="h6">Submitted files</h3>
                <div className="d-flex flex-wrap gap-2">
                  {submission.files.map((file) => (
                    <span className="badge text-bg-light border" key={file}>
                      {file}
                    </span>
                  ))}
                </div>

                <h3 className="h6 mt-4">Rubric</h3>
                <div className="admin-mentor-rubric-grid">
                  {submission.rubric.map((item) => (
                    <div className="border rounded p-3" key={item.criteria}>
                      <div className="d-flex justify-content-between gap-3">
                        <strong>{item.criteria}</strong>
                        <span className="badge text-bg-light border">{item.weight}%</span>
                      </div>
                      <p className="small text-secondary mb-0 mt-2">{item.scoreHint}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>

          <div className="col-12 col-xl-5">
            <div className="card admin-mentor-card">
              <div className="card-header bg-white">
                <h2 className="h5 mb-0">Submit review</h2>
              </div>
              <form className="card-body" noValidate onSubmit={handleSubmit}>
                {reviewResult ? (
                  <div className="alert alert-success" role="alert">
                    Review saved with result <strong>{reviewResult.result}</strong>.
                  </div>
                ) : null}

                <div className="mb-3">
                  <label className="form-label" htmlFor="review-result">
                    Result
                  </label>
                  <select
                    className="form-select"
                    disabled={Boolean(reviewResult)}
                    id="review-result"
                    onChange={(event) => updateForm('result', event.target.value)}
                    value={form.result}
                  >
                    <option value="PASS">PASS</option>
                    <option value="FAIL">FAIL</option>
                  </select>
                </div>

                <div className="mb-3">
                  <label className="form-label" htmlFor="review-feedback">
                    Feedback
                  </label>
                  <textarea
                    className="form-control admin-mentor-feedback-box"
                    disabled={Boolean(reviewResult)}
                    id="review-feedback"
                    onChange={(event) => updateForm('feedback', event.target.value)}
                    placeholder="Nhap feedback ro rang cho learner"
                    value={form.feedback}
                  />
                  <div className={`form-text ${feedbackLength < MIN_FEEDBACK_LENGTH ? 'text-danger' : ''}`}>
                    {feedbackHelp}
                  </div>
                </div>

                <button className="btn btn-primary w-100" disabled={!canSubmit} type="submit">
                  {submitting ? 'Submitting...' : 'Submit review'}
                </button>
              </form>
            </div>
          </div>
        </div>
      ) : null}
    </AdminMentorLayout>
  );
}
